import React from 'react';

const HowItWorks = () => {
    const colors = { cardBg: '#120b06', border: '1px solid #262626', textMain: '#fef3c7', accent: '#ea580c', textMuted: '#a3a3a3' };

    const steps = [
        { title: '📝 Daftar Akun Gratis', desc: 'Isi data diri dan buat profil profesionalmu dalam 2 menit' },
        { title: '🔍 Temukan Lowongan Ideal', desc: 'Filter berdasarkan skill, lokasi, dan gaji yang kamu inginkan' },
        { title: '📄 Kirim Lamaran Cepat', desc: 'Lamar pekerjaan impian dengan sekali klik, pantau status secara real-time' }
    ];

    return (
        <section style={{ padding: '80px 40px', background: '#080402', borderTop: colors.border }}>
            <div style={{ textAlign: 'center', marginBottom: '60px' }}>
                <span style={{ color: colors.accent, fontSize: '13px', fontWeight: '700', letterSpacing: '2px', textTransform: 'uppercase' }}>Proses Mudah</span>
                <h2 style={{ color: colors.textMain, fontSize: '2.5rem', marginTop: '12px', fontWeight: '800', letterSpacing: '-0.02em' }}>
                    3 Langkah Menuju <span style={{ color: colors.accent }}>Sukses</span>
                </h2>
                <p style={{ color: colors.textMuted, marginTop: '12px' }}>Dari pendaftaran hingga diterima kerja, kami dampingi setiap prosesnya</p>
            </div>
            <div style={{ display: 'grid', gridTemplateColumns: 'repeat(auto-fit, minmax(280px, 1fr))', gap: '30px', maxWidth: '1100px', margin: '0 auto' }}>
                {steps.map((step, i) => (
                    <div key={i} style={{ 
                        padding: '35px 25px', 
                        background: colors.cardBg, 
                        border: colors.border, 
                        borderRadius: '20px', 
                        textAlign: 'center',
                        transition: 'all 0.3s ease',
                        position: 'relative',
                        overflow: 'hidden'
                    }}
                    onMouseEnter={(e) => {
                        e.currentTarget.style.transform = 'translateY(-8px)';
                        e.currentTarget.style.borderColor = colors.accent;
                        e.currentTarget.style.boxShadow = '0 15px 30px rgba(0,0,0,0.3)';
                    }}
                    onMouseLeave={(e) => {
                        e.currentTarget.style.transform = 'translateY(0)';
                        e.currentTarget.style.borderColor = '#262626';
                        e.currentTarget.style.boxShadow = 'none';
                    }}>
                        <div style={{ 
                            width: '70px', 
                            height: '70px', 
                            background: `linear-gradient(135deg, ${colors.accent} 0%, #f59e0b 100%)`, 
                            borderRadius: '50%', 
                            margin: '0 auto 20px', 
                            display: 'flex', 
                            alignItems: 'center', 
                            justifyContent: 'center', 
                            color: '#fff', 
                            fontWeight: '800',
                            fontSize: '28px',
                            boxShadow: '0 8px 20px rgba(234,88,12,0.3)'
                        }}>
                            {i + 1}
                        </div>
                        <h3 style={{ color: colors.textMain, fontWeight: '800', marginBottom: '12px', fontSize: '20px' }}>{step.title}</h3>
                        <p style={{ color: colors.textMuted, fontSize: '14px', lineHeight: '1.6' }}>{step.desc}</p>
                    </div>
                ))}
            </div>
        </section>
    );
};
export default HowItWorks;
